import { useEffect, useState } from "react";
import API_URL from "../api"; // Import the API base URL

function Home() {
  const [capsules, setCapsules] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch capsules from the backend
    fetch(`${API_URL}/api/memoryHaven`)
      .then((response) => response.json())
      .then((data) => {
        setCapsules(data);
        setLoading(false);
      })
      .catch((error) => {
        console.error("Error fetching capsules:", error);
        setLoading(false);
      });
  }, []);

  return (
    <div>
      <h1>Welcome to Memory Haven</h1>
      <p>Save the present, gift it to the future!</p>

      <h2>Recent Capsules</h2>
      {loading ? (
        <p>Loading...</p>
      ) : capsules.length > 0 ? (
        <ul>
          {capsules.map((capsule) => (
            <li key={capsule.id}>
              <h3>{capsule.title}</h3>
              <p>{capsule.description}</p>
            </li>
          ))}
        </ul>
      ) : (
        <p>No capsules found. Create one now!</p>
      )}
    </div>
  );
}

export default Home;
